                new StatusUpdate { Description = "Departed facility", Location = "Philadelphia, PA", Timestamp = new DateTime(2026, 5, 26, 6, 0, 0) },
                new StatusUpdate { Description = "In transit", Location = "Chicago, IL", Timestamp = new DateTime(2026, 5, 26, 22, 15, 0) },
            ]
        },
        ["PKG-2002"] = new Shipment
        {
            TrackingNumber = "PKG-2002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTime(2026, 5, 24),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Seattle, WA", Timestamp = new DateTime(2026, 5, 20, 10, 0, 0) },
                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = new DateTime(2026, 5, 21, 14, 0, 0) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = new DateTime(2026, 5, 23, 8, 0, 0) },
                new StatusUpdate { Description = "Delivered", Location = "San Francisco, CA", Timestamp = new DateTime(2026, 5, 23, 12, 45, 0) },
            ]
        },
        ["PKG-3003"] = new Shipment
        {
            TrackingNumber = "PKG-3003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTime(2026, 6, 5),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Dallas, TX", Timestamp = new DateTime(2026, 5, 27, 7, 0, 0) },
            ]
        },
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (Shipments.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
    }
